// Simulated priority queue using sorted insert
function insertSorted(arr, val) {
  let i = arr.length - 1;
  arr.push(val);
  while (i >= 0 && arr[i] > val) {
    arr[i + 1] = arr[i];
    i--;
  }
  arr[i + 1] = val;
}

